export const CASO_EPSA_HTML = "\n\n\n\n<!-- HERO -->\n<header class=\"cs-hero\">\n  <div class=\"cs-hero__inner\">\n    <div class=\"cs-eyebrow\">Caso de \u00e9xito \u00b7 EPSA \u00b7 <span style=\"color:#5fe1a3;\">Finalizado</span></div>\n    <h1 class=\"cs-title\">Puerto Exterior San Antonio. <em>Adenda Extraordinaria cerrada.</em></h1>\n    <p class=\"cs-lede\">Una evaluaci\u00f3n con 1.472 consultas ciudadanas y cerca de 25 organismos revisando en paralelo. Inventures acompa\u00f1\u00f3 a EPSA con herramientas de IA para clasificar, agrupar y preparar borradores \u2014 sin redactar por el titular ni por sus consultoras.</p>\n  </div>\n</header>\n\n<!-- FRANJA SOBRIA -->\n<section class=\"cs-facts\">\n  <div class=\"cs-facts__inner\">\n    <div class=\"cs-fact\">\n      <div class=\"cs-fact__label\">Proyecto</div>\n      <div class=\"cs-fact__value\">Puerto <em>Exterior</em></div>\n      <div class=\"cs-fact__sub\">San Antonio \u00b7 EPSA</div>\n    </div>\n    <div class=\"cs-fact\">\n      <div class=\"cs-fact__label\">Inversi\u00f3n</div>\n      <div class=\"cs-fact__value\">~USD <em>4.000 MM</em></div>\n      <div class=\"cs-fact__sub\">Obra portuaria mayor</div>\n    </div>\n    <div class=\"cs-fact\">\n      <div class=\"cs-fact__label\">Etapa</div>\n      <div class=\"cs-fact__value\">Adenda <em>Extraordinaria</em></div>\n      <div class=\"cs-fact__sub\">Tercera evaluaci\u00f3n \u00b7 cerrada</div>\n    </div>\n    <div class=\"cs-fact\">\n      <div class=\"cs-fact__label\">PAC agrupada</div>\n      <div class=\"cs-fact__value\"><em>1.472 \u2192 622</em></div>\n      <div class=\"cs-fact__sub\">58 % de consultas agrupadas por similitud</div>\n    </div>\n  </div>\n</section>\n\n<!-- Imagen contenida del proyecto -->\n<figure class=\"cs-photo\" aria-label=\"Puerto Exterior San Antonio\">\n  <div class=\"cs-photo__frame\">\n    <figcaption class=\"cs-photo__caption\">Puerto Exterior \u00b7 San Antonio \u00b7 Regi\u00f3n de Valpara\u00edso</figcaption>\n  </div>\n</figure>\n\n<!-- NARRATIVA -->\n<section class=\"cs-body\">\n  <div class=\"cs-body__inner\">\n\n    <!-- 01 \u00b7 CONSULTOR\u00cdA -->\n    <div class=\"cs-block\">\n      <div class=\"cs-block__label\">01 \u00b7 Consultor\u00eda</div>\n      <h2>Acompa\u00f1ar, no reemplazar.</h2>\n      <p>Inventures <strong>no redact\u00f3 el EIA</strong>. Ese rol fue del titular y de sus consultoras. Lo que hicimos fue ponernos al lado del equipo t\u00e9cnico con herramientas de IA que absorbieran las partes mec\u00e1nicas del proceso: clasificaci\u00f3n, b\u00fasqueda de equivalencias, primeros borradores, revisi\u00f3n de consistencia. As\u00ed el criterio experto se concentr\u00f3 donde s\u00ed era no delegable.</p>\n      <p>El acompa\u00f1amiento arranc\u00f3 en la <strong>Adenda 2</strong> con dos frentes: revisi\u00f3n de consistencia entre cap\u00edtulos y siete cap\u00edtulos de <strong>fichas resumen con GenAI</strong> para la revisi\u00f3n interna del equipo y los abogados. Con ese setup afinado, entramos a la <strong>Adenda Extraordinaria</strong>, que tra\u00eda en paralelo un ICSARA T\u00e9cnico de unos veinticinco OAECAs y un ICSARA Ciudadano con m\u00e1s de mil cuatrocientas consultas.</p>\n    </div>\n\n    <!-- 02 \u00b7 OPORTUNIDADES DETECTADAS -->\n    <div class=\"cs-block\">\n      <div class=\"cs-block__label\">02 \u00b7 Oportunidades detectadas</div>\n      <h2>Lo que la IA <em>s\u00ed</em> pod\u00eda resolver antes de llegar al experto.</h2>\n\n      <div class=\"cs-deliv\">\n        <div class=\"cs-deliv__row\">\n          <div class=\"cs-deliv__k\">01</div>\n          <div class=\"cs-deliv__t\"><strong>Consultas ciudadanas duplicadas</strong><span>Miles de consultas sobre los mismos temas, redactadas con palabras distintas. Responderlas una a una es trabajo mec\u00e1nico que diluye criterio.</span></div>\n          <div class=\"cs-deliv__tool\">Agrupaci\u00f3n</div>\n        </div>\n        <div class=\"cs-deliv__row\">\n          <div class=\"cs-deliv__k\">02</div>\n          <div class=\"cs-deliv__t\"><strong>Consistencia entre EIA, Adenda 1 y Adenda 2</strong><span>Cada respuesta nueva ten\u00eda que alinearse con lo ya declarado, o explicar expl\u00edcitamente el cambio.</span></div>\n          <div class=\"cs-deliv__tool\">Consistencia</div>\n        </div>\n        <div class=\"cs-deliv__row\">\n          <div class=\"cs-deliv__k\">03</div>\n          <div class=\"cs-deliv__t\"><strong>Respuestas ciudadanas obsoletas de rondas anteriores</strong><span>Reusar una respuesta vieja era riesgoso: el proyecto y los compromisos hab\u00edan evolucionado. Hab\u00eda que actualizar respuesta por respuesta.</span></div>\n          <div class=\"cs-deliv__tool\">Drafts</div>\n        </div>\n        <div class=\"cs-deliv__row\">\n          <div class=\"cs-deliv__k\">04</div>\n          <div class=\"cs-deliv__t\"><strong>Revisi\u00f3n final de completitud</strong><span>Confirmar que cada observaci\u00f3n qued\u00f3 respondida, sin omisiones ni contradicciones con adendas anteriores. Humanamente imposible en plazos reales.</span></div>\n          <div class=\"cs-deliv__tool\">Consistencia</div>\n        </div>\n      </div>\n    </div>\n\n    <!-- EJEMPLO A/B: dos consultas ciudadanas equivalentes -->\n    <div class=\"cs-block\">\n      <div class=\"cs-block__label\">Evidencia \u00b7 Agrupaci\u00f3n</div>\n      <h2>De <em>1.472 consultas</em> a 622 madres. El mismo tema, distinto n\u00famero.</h2>\n      <p>El modelo identific\u00f3 850 consultas como variantes ling\u00fc\u00edsticas de otras. Ejemplo real del expediente:</p>\n\n      <div class=\"cs-ab\">\n        <div class=\"cs-ab__col\">\n          <div class=\"cs-ab__k\">Consulta A \u00b7 N\u00b0212</div>\n          <p>\u00abEn relaci\u00f3n a las compensaciones se solicita al titular informar qu\u00e9 par\u00e1metros, modelo y/o gu\u00eda utiliz\u00f3 para definir las compensaciones y los lugares y formas en que realizar\u00e1 las compensaciones y mitigaciones; si realiz\u00f3 alguna reuni\u00f3n de coordinaci\u00f3n con autoridades comunales, juntas de vecinos o miembros de la comunidad que se ver\u00e1n afectados.\u00bb</p>\n        </div>\n        <div class=\"cs-ab__col\">\n          <div class=\"cs-ab__k\">Consulta B \u00b7 N\u00b0893</div>\n          <p>\u00abEn relaci\u00f3n a las compensaciones, se solicita al Titular que informe qu\u00e9 par\u00e1metros, modelos y/o gu\u00edas utiliz\u00f3 para definir las mitigaciones, los lugares y la forma en que \u00e9stas se concretar\u00e1n; si realiz\u00f3 reuni\u00f3n de coordinaci\u00f3n o consulta con autoridades comunales, juntas de vecinos o miembros de las comunidades que se ver\u00e1n afectadas, enti\u00e9ndase San Antonio y Santo Domingo, al menos.\u00bb</p>\n        </div>\n      </div>\n      <p class=\"cs-ab__note\">Mismo tema, dos consultas ingresadas con n\u00famero distinto por el SEA. El sistema las marc\u00f3 como equivalentes y asign\u00f3 una \u00fanica respuesta madre. El equipo experto redact\u00f3 una vez, no dos.</p>\n    </div>\n\n    <!-- 03 \u00b7 ACELERAMOS CON IA -->\n    <div class=\"cs-block\">\n      <div class=\"cs-block__label\">03 \u00b7 Aceleramos con IA</div>\n      <h2>Tres fases operativas, desplegadas en orden.</h2>\n\n      <div class=\"cs-deliv\">\n        <div class=\"cs-deliv__row\">\n          <div class=\"cs-deliv__k\">Fase 01</div>\n          <div class=\"cs-deliv__t\"><strong>Preparaci\u00f3n Pre-ICSARA</strong><span>Con las observaciones preliminares que el equipo ya recog\u00eda en planilla, clasificamos por tema (marino, tr\u00e1fico, ruido, biodiversidad, social), agrupamos consultas equivalentes entre OAECAs y ciudadanos, y generamos borradores tempranos citando EIA, Adenda 1 y Adenda 2. Alertamos adem\u00e1s qu\u00e9 observaciones suger\u00edan estudios complementarios, para planificarlos con anticipaci\u00f3n.</span></div>\n          <div class=\"cs-deliv__tool\">Agrupaci\u00f3n \u00b7 Drafts</div>\n        </div>\n        <div class=\"cs-deliv__row\">\n          <div class=\"cs-deliv__k\">Fase 02</div>\n          <div class=\"cs-deliv__t\"><strong>Respuesta al ICSARA Consolidado</strong><span>Recibido el ICSARA oficial (T\u00e9cnico + Ciudadano), el agente gener\u00f3 respuestas detalladas citando documento y p\u00e1gina. Para observaciones de alta especificidad (modelaciones, criterios legales) el trabajo sigui\u00f3 con los abogados de EPSA y consultores externos. La IA prepar\u00f3 el borrador; la validaci\u00f3n experta fue no delegable.</span></div>\n          <div class=\"cs-deliv__tool\">Drafts</div>\n        </div>\n        <div class=\"cs-deliv__row\">\n          <div class=\"cs-deliv__k\">Fase 03</div>\n          <div class=\"cs-deliv__t\"><strong>Revisi\u00f3n de Consistencia y Completitud</strong><span>Sobre la adenda final corrieron los agentes de completitud y consistencia: omisiones (partes de una observaci\u00f3n sin abordar), contradicciones entre respuestas, desajustes con el EIA o las adendas anteriores. Mismas herramientas de la Adenda 2, refinadas con los aprendizajes de ese ciclo.</span></div>\n          <div class=\"cs-deliv__tool\">Consistencia</div>\n        </div>\n      </div>\n    </div>\n\n  </div>\n</section>\n\n<!-- CTA -->\n<section class=\"cs-cta\">\n  <div class=\"cs-cta__inner\">\n    <h3>Mismo criterio t\u00e9cnico. <em>Una fracci\u00f3n del tiempo.</em></h3>\n    <a href=\"mailto:evalia@inventures.cl\" class=\"ev-btn ev-btn--primary\">Agendar reuni\u00f3n <span class=\"ev-btn__arrow\">\u2192</span></a>\n  </div>\n</section>\n\n\n\n\n\n<!-- @bundle-js: js/nav.js js/landing.js -->\n<!-- @end-bundle -->\n";

export const CASO_EPSA_JS = "\n/* === js/nav.js === */\n/* ============================================================\n   EVALIA \u00b7 NAV + FOOTER UNIVERSAL\n   Inyecta la misma barra superior y footer en cada p\u00e1gina.\n   - En p\u00e1ginas ra\u00edz (index/an\u00e1lisis/caso/demos)  \u2192 base = ./\n   - En p\u00e1ginas dentro de subcarpeta (analisis/ o demos/) \u2192 base = ../\n   ============================================================ */\n(() => {\n  'use strict';\n\n  // \u2500\u2500 base path \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n  const parts = location.pathname.split('/').filter(Boolean);\n  const isSub = parts.length >= 2 && /^(analisis|demos)$/i.test(parts[parts.length - 2]);\n  const base = isSub ? '../' : './';\n\n  // \u2500\u2500 current tab \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n  function detectCurrent() {\n    const p = location.pathname;\n    if (/\\/demos\\.html/i.test(p)) return 'demos';\n    if (/\\/demos\\//i.test(p)) return 'demos';\n    if (/\\/analisis(\\.html|\\/)/i.test(p)) return 'analisis';\n    return 'inicio';\n  }\n\n  // \u2500\u2500 HTML \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n  function navHTML(current) {\n    const on = (k) => current === k ? ' class=\"is-current\"' : '';\n    const trigOn = current === 'analisis' ? ' is-current' : '';\n    return `\n      <div class=\"ev-site-nav__left\">\n        <a href=\"${base}index.html\" aria-label=\"Evalia \u2014 Inicio\" class=\"ev-nav-brand\">\n          <img src=\"${base}assets/evalia-logo-white.svg\" alt=\"Evalia\" class=\"ev-nav-brand__logo\" />\n          <span class=\"ev-nav-brand__by\">por Inventures</span>\n        </a>\n      </div>\n      <div class=\"ev-site-nav__right\">\n        <div class=\"nav-group\">\n          <a href=\"${base}index.html#que-es\"${on('inicio')}>Qu\u00e9 es</a>\n          <a href=\"${base}index.html#como-funciona\">C\u00f3mo funciona</a>\n          <a href=\"${base}index.html#evaluacion-ambiental\">Evaluaci\u00f3n ambiental</a>\n          <a href=\"${base}demos.html\"${on('demos')}>Demos</a>\n          <a href=\"${base}index.html#seguridad\">Seguridad</a>\n          <a href=\"${base}index.html#qa\">Preguntas</a>\n        </div>\n        <span class=\"nav-divider\"></span>\n        <div class=\"nav-dropdown\">\n          <button type=\"button\" class=\"nav-dropdown__trigger${trigOn}\" aria-haspopup=\"true\" aria-expanded=\"false\">Estudios<span class=\"nav-dropdown__chevron\" aria-hidden=\"true\">\u25be</span></button>\n          <div class=\"nav-dropdown__menu\" role=\"menu\">\n            <a href=\"${base}analisis.html\" class=\"nav-dropdown__head\" role=\"menuitem\">Ver todos los estudios <span class=\"arr\">\u2192</span></a>\n            <a href=\"${base}analisis/antofagasta-carga.html\" role=\"menuitem\">Carga documental \u00b7 Antofagasta</a>\n            <a href=\"${base}analisis/etapas-seia.html\" role=\"menuitem\">Tiempos por etapa SEIA</a>\n            <a href=\"${base}analisis/responsables-estatales.html\" role=\"menuitem\">Responsables estatales</a>\n            <a href=\"${base}analisis/organizaciones.html\" role=\"menuitem\">Ranking por organismo</a>\n          </div>\n        </div>\n        <a href=\"${base}index.html#proximos\" class=\"cta\">Agendar demo</a>\n      </div>`;\n  }\n\n  function footerHTML() {\n    return `\n      <div class=\"ev-site-footer__left\">\n        <div class=\"ev-footer__brand\">\n          <img src=\"${base}assets/evalia-logo-white.svg\" alt=\"Evalia\" class=\"ev-footer__logo\" />\n          <span class=\"ev-footer__by\">por Inventures</span>\n        </div>\n        <div class=\"ev-footer__tag\">IA aplicada al ciclo EIA/DIA. Evalia es una operaci\u00f3n interna de Inventures: consultor\u00eda y tecnolog\u00eda para los proyectos de inversi\u00f3n que el pa\u00eds necesita sacar adelante.</div>\n      </div>\n      <div class=\"ev-site-footer__mid\">\n        <div class=\"ev-footer__eyebrow\">Producto de</div>\n        <a href=\"https://inventures.cl\" target=\"_blank\" rel=\"noopener\" class=\"ev-footer__inv-name\">Inventures <span class=\"ev-footer__external-note\">inventures.cl \u2197</span></a>\n      </div>\n      <div class=\"ev-site-footer__right\">\n        <div class=\"ev-footer__eyebrow\">Contacto</div>\n        <a href=\"mailto:evalia@inventures.cl\" class=\"ev-footer__mail\">evalia@inventures.cl</a>\n        <div class=\"ev-footer__loc\">Santiago \u00b7 Chile \u00b7 2026</div>\n      </div>`;\n  }\n\n  // \u2500\u2500 mount \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n  function mount() {\n    const current = detectCurrent();\n\n    // NAV\n    let nav = document.querySelector('nav.ev-site-nav');\n    if (!nav) {\n      nav = document.createElement('nav');\n      nav.className = 'ev-site-nav';\n      document.body.insertBefore(nav, document.body.firstChild);\n    }\n    nav.id = 'site-nav';\n    nav.innerHTML = navHTML(current);\n\n    // FOOTER \u2014 s\u00f3lo si ya existe un <footer.ev-site-footer> lo sobreescribimos\n    const f = document.querySelector('footer.ev-site-footer');\n    if (f) {\n      f.innerHTML = footerHTML();\n    }\n\n    // Nav solid-on-scroll (replica el comportamiento de landing.js para\n    // que las p\u00e1ginas que no cargan landing.js \u2014 como las demos \u2014 tambi\u00e9n\n    // tengan nav blanco al hacer scroll).\n    if (!window.__evNavScrollBound) {\n      window.__evNavScrollBound = true;\n      const onScroll = () => nav.classList.toggle('is-solid', window.scrollY > 60);\n      window.addEventListener('scroll', onScroll, { passive: true });\n      onScroll();\n    }\n  }\n\n  if (document.readyState === 'loading') {\n    document.addEventListener('DOMContentLoaded', mount);\n  } else {\n    mount();\n  }\n})();\n\n\n/* === js/landing.js === */\n/* ============================================================\n   EVALIA \u00b7 LANDING JS\n   - Nav solida al scrollear\n   - Reveal on scroll (IntersectionObserver)\n   - Panel de tweaks (dev) sincronizado entre p\u00e1ginas via localStorage\n   ============================================================ */\n\n(() => {\n  'use strict';\n\n  const LS_KEY = 'evalia.tweaks.v1';\n\n  // Valores por defecto. Editables a mano por el equipo desde el HTML.\n  const TWEAK_DEFAULTS = /*EDITMODE-BEGIN*/{\n    accent: 'green'\n  }/*EDITMODE-END*/;\n\n  // Lee tweaks persistidos de localStorage (si existen) y los mergea.\n  function readState() {\n    try {\n      const raw = localStorage.getItem(LS_KEY);\n      if (!raw) return { ...TWEAK_DEFAULTS };\n      const parsed = JSON.parse(raw);\n      return { ...TWEAK_DEFAULTS, ...parsed };\n    } catch (_) {\n      return { ...TWEAK_DEFAULTS };\n    }\n  }\n  function writeState(s) {\n    try { localStorage.setItem(LS_KEY, JSON.stringify(s)); } catch (_) {}\n  }\n\n  const state = readState();\n\n  function applyAccent(accent) {\n    if (!accent) return;\n    document.body.dataset.accent = accent;\n  }\n\n  // Aplicar el accent global antes de cualquier otra cosa para evitar flash.\n  applyAccent(state.accent);\n\n  /* \u2500\u2500 Nav: fondo s\u00f3lido al scrollear \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n  const nav = document.getElementById('site-nav');\n  if (nav) {\n    const onScroll = () => nav.classList.toggle('is-solid', window.scrollY > 60);\n    window.addEventListener('scroll', onScroll, { passive: true });\n    onScroll();\n  }\n\n  /* \u2500\u2500 Reveal on scroll \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n  const revealEls = document.querySelectorAll('.ev-reveal');\n  if (revealEls.length) {\n    const io = new IntersectionObserver((entries) => {\n      entries.forEach((e) => {\n        if (e.isIntersecting) {\n          e.target.classList.add('is-visible');\n          io.unobserve(e.target);\n        }\n      });\n    }, { threshold: 0.08, rootMargin: '0px 0px -60px 0px' });\n    revealEls.forEach((el) => io.observe(el));\n  }\n\n  /* \u2500\u2500 Sincronizaci\u00f3n entre pesta\u00f1as via storage event \u2500\u2500 */\n  window.addEventListener('storage', (ev) => {\n    if (ev.key !== LS_KEY) return;\n    try {\n      const next = JSON.parse(ev.newValue || '{}');\n      if (next.accent) { state.accent = next.accent; applyAccent(state.accent); paintPanel(); }\n    } catch (_) {}\n  });\n\n  /* \u2500\u2500 Panel de tweaks (dev) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n  const panel = document.getElementById('tweaks-panel');\n  if (!panel) {\n    // La p\u00e1gina no monta panel (ej. detalle de an\u00e1lisis), pero igual persistimos\n    // el estilo desde localStorage, que ya est\u00e1 aplicado arriba.\n    try { window.parent.postMessage({ type: '__edit_mode_available' }, '*'); } catch (_) {}\n    return;\n  }\n\n  function paintPanel() {\n    panel.querySelectorAll('.ev-tweaks__seg').forEach((seg) => {\n      const key = seg.dataset.group;\n      seg.querySelectorAll('button').forEach((b) => {\n        b.classList.toggle('is-on', b.dataset.val === state[key]);\n      });\n    });\n  }\n  paintPanel();\n\n  panel.querySelectorAll('.ev-tweaks__seg').forEach((seg) => {\n    seg.addEventListener('click', (ev) => {\n      const btn = ev.target.closest('button[data-val]');\n      if (!btn) return;\n      const key = seg.dataset.group;\n      state[key] = btn.dataset.val;\n      if (key === 'accent') applyAccent(state.accent);\n      paintPanel();\n      writeState(state);\n      try {\n        window.parent.postMessage(\n          { type: '__edit_mode_set_keys', edits: { [key]: btn.dataset.val } },\n          '*'\n        );\n      } catch (_) {}\n    });\n  });\n\n  window.addEventListener('message', (ev) => {\n    const d = ev.data || {};\n    if (d.type === '__activate_edit_mode') panel.classList.add('is-on');\n    else if (d.type === '__deactivate_edit_mode') panel.classList.remove('is-on');\n  });\n\n  try { window.parent.postMessage({ type: '__edit_mode_available' }, '*'); } catch (_) {}\n})();\n\n/* ============================================================\n   FLUJO HERRAMIENTAS \u00b7 Interacci\u00f3n rail \u2194 detalle\n   ============================================================ */\n(() => {\n  'use strict';\n\n  const rail = document.querySelector('.ev-flow__rail');\n  const detail = document.getElementById('flow-detail');\n  const dataEl = document.getElementById('ev-tools-data');\n  if (!rail || !detail || !dataEl) return;\n\n  let data;\n  try { data = JSON.parse(dataEl.textContent); } catch (_) { return; }\n  const { tools, phases } = data;\n\n  const esc = (s) => String(s).replace(/[&<>\"']/g, (c) => ({'&':'&amp;','<':'&lt;','>':'&gt;','\"':'&quot;',\"'\":'&#39;'}[c]));\n\n  function render(phaseId) {\n    const phaseName = phases[phaseId] || '';\n    const btn = rail.querySelector(`[data-phase=\"${phaseId}\"]`);\n    const ids = (btn?.dataset.tools || '').split(',').filter(Boolean);\n\n    let html = '';\n    if (ids.length === 0) {\n      html = `\n        <div class=\"ev-flow__soon\">\n          <div>\n            <h4>En construcci\u00f3n <em>\u00b7 pr\u00f3xima ventana de producto.</em></h4>\n            <p>Estamos evaluando qu\u00e9 parte de esta etapa es mec\u00e1nica, qu\u00e9 parte es criterio t\u00e9cnico del cliente y d\u00f3nde un agente puede aportar sin erosionar la decisi\u00f3n experta. Si tienes un dolor concreto en esta etapa, escr\u00edbenos para ayudarnos a priorizar: <a href=\"mailto:evalia@inventures.cl?subject=Fase%20${encodeURIComponent(phaseName)}\">cont\u00e1ctanos</a>.</p>\n          </div>\n          <div class=\"ev-flow__soon-badge\">Pr\u00f3ximamente</div>\n        </div>`;\n    } else {\n      const cards = ids.map((k) => {\n        const t = tools[k];\n        if (!t) return '';\n        return `\n          <article class=\"ev-tool-card\" data-tool-open=\"${esc(t.id)}\" tabindex=\"0\" role=\"button\" aria-label=\"Ver detalle de ${esc(t.name)}\">\n            <h3 class=\"ev-tool-card__title\">${esc(t.name)}</h3>\n            <p class=\"ev-tool-card__body\">${t.short || t.body}</p>\n            <div class=\"ev-tool-card__cta\">Ver detalle <span class=\"arr\">\u2192</span></div>\n          </article>`;\n      }).join('');\n      html = `<div class=\"ev-flow__tools-grid\">${cards}</div>`;\n    }\n\n    detail.classList.add('is-fading');\n    setTimeout(() => {\n      detail.innerHTML = html;\n      detail.classList.remove('is-fading');\n    }, 120);\n  }\n\n  rail.addEventListener('click', (ev) => {\n    const btn = ev.target.closest('.ev-flow__phase');\n    if (!btn) return;\n    rail.querySelectorAll('.ev-flow__phase').forEach((b) => {\n      b.classList.toggle('is-active', b === btn);\n      b.setAttribute('aria-selected', b === btn ? 'true' : 'false');\n    });\n    render(btn.dataset.phase);\n  });\n\n  rail.addEventListener('keydown', (ev) => {\n    const btn = ev.target.closest('.ev-flow__phase');\n    if (!btn) return;\n    const all = [...rail.querySelectorAll('.ev-flow__phase')];\n    const idx = all.indexOf(btn);\n    if (ev.key === 'ArrowRight' || ev.key === 'ArrowLeft') {\n      ev.preventDefault();\n      const next = ev.key === 'ArrowRight' ? (idx + 1) % all.length : (idx - 1 + all.length) % all.length;\n      all[next].focus();\n      all[next].click();\n    }\n  });\n\n  // Render inicial: la fase marcada como is-active (Adenda por default)\n  const initial = rail.querySelector('.ev-flow__phase.is-active') || rail.querySelector('.ev-flow__phase');\n  if (initial) render(initial.dataset.phase);\n\n  /* \u2500\u2500 Modal de detalle de herramienta \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n  const modal = document.getElementById('tool-modal');\n  if (!modal) return;\n  const titleEl = document.getElementById('tool-modal-title');\n  const bodyEl = document.getElementById('tool-modal-body');\n  const usesEl = document.getElementById('tool-modal-uses');\n  const noteEl = document.getElementById('tool-modal-note');\n\n  function openModal(toolId){\n    const t = tools[toolId];\n    if (!t) return;\n    titleEl.textContent = t.name;\n    bodyEl.innerHTML = t.body;\n    usesEl.innerHTML = (t.uses || []).map(u => `<li>${esc(u)}</li>`).join('');\n    noteEl.textContent = t.note || '';\n    modal.classList.add('is-open');\n    modal.setAttribute('aria-hidden', 'false');\n    document.body.style.overflow = 'hidden';\n  }\n  function closeModal(){\n    modal.classList.remove('is-open');\n    modal.setAttribute('aria-hidden', 'true');\n    document.body.style.overflow = '';\n  }\n\n  detail.addEventListener('click', (ev) => {\n    const card = ev.target.closest('[data-tool-open]');\n    if (!card) return;\n    openModal(card.dataset.toolOpen);\n  });\n  detail.addEventListener('keydown', (ev) => {\n    const card = ev.target.closest('[data-tool-open]');\n    if (!card) return;\n    if (ev.key === 'Enter' || ev.key === ' ') {\n      ev.preventDefault();\n      openModal(card.dataset.toolOpen);\n    }\n  });\n  modal.addEventListener('click', (ev) => {\n    if (ev.target.closest('[data-close]')) closeModal();\n  });\n  document.addEventListener('keydown', (ev) => {\n    if (ev.key === 'Escape' && modal.classList.contains('is-open')) closeModal();\n  });\n})();\n\n";

export const CASO_EPSA_CSS = "\n.ev-site-nav__right .nav-group{ display:flex; gap:28px; align-items:center; }\n.ev-site-nav__right .nav-divider{ width:1px; height:16px; background: currentColor; opacity:0.25; }\n.ev-site-nav__right a.is-current{ color: var(--ev-accent); }\n\n/* Hero SOBRIO estilo an\u00e1lisis (navy s\u00f3lido, sin foto) */\n.cs-hero{\n  position: relative; isolation: isolate;\n  background: var(--ev-navy-900); color:#fff;\n  padding: 140px 48px 72px;\n  overflow: hidden;\n  font-family: var(--ev-font-body);\n}\n.cs-hero::before{ content:''; position:absolute; inset:0; z-index:-1;\n  background: radial-gradient(ellipse 60% 60% at 18% 30%, rgba(0,198,223,0.12), transparent 60%); }\n.cs-hero__inner{ max-width: 1360px; margin: 0 auto; width: 100%; }\n.cs-eyebrow{\n  font-family: var(--ev-font-mono); font-size:11px; letter-spacing:3px; text-transform:uppercase;\n  color: var(--ev-accent); font-weight:500;\n  display:inline-flex; align-items:center; gap:10px; margin-bottom: 28px;\n}\n.cs-eyebrow::before{ content:''; width:36px; height:1px; background: var(--ev-accent); }\n.cs-title{\n  font-size: var(--ev-fs-page-title); font-weight: 300; line-height: var(--ev-lh-page-title);\n  letter-spacing: var(--ev-ls-page-title); max-width: 1000px; color:#fff;\n  margin: 0; text-wrap: balance;\n}\n.cs-title em{ font-style:normal; color: var(--ev-accent); font-weight:300; }\n.cs-lede{\n  margin-top: 28px; font-size: 16px; line-height: 1.75; max-width: 680px;\n  color: rgba(255,255,255,0.78); font-weight: 300;\n}\n\n/* Franja de cifras */\n.cs-facts{\n  background: var(--ev-bg); padding: 56px 48px;\n  border-bottom: 1px solid var(--ev-line);\n}\n.cs-facts__inner{ max-width: 1360px; margin: 0 auto; display: grid; grid-template-columns: repeat(4, 1fr); gap: 0; }\n.cs-fact{\n  padding: 0 32px;\n  border-right: 1px solid var(--ev-line);\n}\n.cs-fact:first-child{ padding-left: 0; }\n.cs-fact:last-child{ border-right: 0; padding-right: 0; }\n.cs-fact__label{\n  font-family: var(--ev-font-mono); font-size:10.5px; letter-spacing:2px;\n  text-transform:uppercase; color: var(--ev-muted); font-weight:500; margin-bottom: 12px;\n}\n.cs-fact__value{\n  font-size: 38px; font-weight: 300; letter-spacing: -0.025em; color: var(--ev-navy-900); line-height:1;\n}\n.cs-fact__value em{ font-style:normal; color: var(--ev-accent); font-weight: 400; }\n.cs-fact__sub{ font-size: 13px; color: var(--ev-muted); margin-top: 10px; font-weight:300; }\n\n/* Imagen contenida (no full-bleed) para preservar calidad */\n.cs-photo{\n  max-width: 880px;\n  margin: 48px auto 0;\n  padding: 0 48px;\n}\n.cs-photo__frame{\n  aspect-ratio: 3 / 2;\n  max-height: 420px;\n  background: var(--ev-navy-900) url('./assets/epsa-puerto-exterior.png?v=2') center center/cover no-repeat;\n  background-position: 50% 50%;\n  position: relative;\n  border-radius: 4px;\n  overflow: hidden;\n}\n.cs-photo__caption{\n  position: absolute; bottom: 16px; left: 20px;\n  font-family: var(--ev-font-mono); font-size: 10.5px; letter-spacing: 2px;\n  text-transform: uppercase; color: #fff;\n  background: rgba(0,33,50,0.72); padding: 7px 12px; border-radius: 2px;\n  backdrop-filter: blur(4px);\n}\n@media (max-width: 900px){\n  .cs-photo{ padding: 0 24px; margin-top: 32px; }\n  .cs-photo__frame{ aspect-ratio: 16 / 10; }\n  .cs-photo__caption{ left: 14px; bottom: 12px; font-size: 10px; }\n}\n\n/* Secciones narrativas */\n.cs-body{ padding: 96px 48px; background: var(--ev-bg); }\n.cs-body__inner{ max-width: 900px; margin: 0 auto; }\n.cs-block + .cs-block{ margin-top: 72px; }\n.cs-block__label{\n  font-family: var(--ev-font-mono); font-size:11px; letter-spacing:3px; text-transform:uppercase;\n  color: var(--ev-accent); font-weight:500;\n  display:inline-flex; align-items:center; gap:10px; margin-bottom: 20px;\n}\n.cs-block__label::before{ content:''; width:24px; height:1px; background: var(--ev-accent); }\n.cs-block h2{\n  font-size: clamp(1.8rem, 3.2vw, 2.6rem); font-weight: 300; line-height: 1.2;\n  letter-spacing: -0.02em; color: var(--ev-navy-900); margin-bottom: 28px;\n}\n.cs-block h2 em{ font-style:normal; color: var(--ev-accent); font-weight:300; }\n.cs-block p{ font-size: 16px; line-height: 1.75; color: var(--ev-navy-900); font-weight: 300; margin-bottom: 20px; }\n.cs-block p strong{ font-weight: 500; color: var(--ev-navy-900); }\n.cs-block blockquote{\n  margin: 40px 0; padding: 28px 32px;\n  border-left: 3px solid var(--ev-accent);\n  background: #FAFBFC;\n  font-size: 18px; line-height: 1.65; font-weight: 300; font-style: italic;\n  color: var(--ev-navy-900); border-radius: 0 4px 4px 0;\n}\n.cs-block blockquote cite{\n  display: block; margin-top: 16px; font-style: normal;\n  font-family: var(--ev-font-mono); font-size: 11px; letter-spacing: 2px;\n  text-transform: uppercase; color: var(--ev-muted); font-weight: 500;\n}\n\n/* Deliverables list */\n.cs-deliv{ margin-top: 32px; display: grid; gap: 0; border-top: 1px solid var(--ev-line); }\n.cs-deliv__row{\n  padding: 24px 0; border-bottom: 1px solid var(--ev-line);\n  display: grid; grid-template-columns: 140px 1fr 180px; gap: 32px; align-items: baseline;\n}\n.cs-deliv__k{ font-family: var(--ev-font-mono); font-size: 11px; letter-spacing: 2px; text-transform: uppercase; color: var(--ev-muted); font-weight: 500; }\n.cs-deliv__t{ font-size: 15px; font-weight: 500; color: var(--ev-navy-900); }\n.cs-deliv__t strong{ display:block; font-weight: 500; margin-bottom: 4px; }\n.cs-deliv__t span{ font-size: 13px; color: var(--ev-muted); font-weight: 300; line-height: 1.6; }\n.cs-deliv__tool{ font-family: var(--ev-font-mono); font-size: 11px; color: var(--ev-accent); letter-spacing: 1.5px; text-transform: uppercase; font-weight: 500; }\n\n/* A/B ejemplo consultas ciudadanas */\n.cs-ab{ display:grid; grid-template-columns: 1fr 1fr; gap: 0; margin-top: 32px;\n  border-top: 1px solid var(--ev-line); border-bottom: 1px solid var(--ev-line); }\n.cs-ab__col{ padding: 28px 32px 28px 0; border-right: 1px solid var(--ev-line); }\n.cs-ab__col:last-child{ border-right: 0; padding: 28px 0 28px 32px; }\n.cs-ab__k{ font-family: var(--ev-font-mono); font-size: 11px; letter-spacing: 2px;\n  text-transform: uppercase; color: var(--ev-accent); font-weight: 500; margin-bottom: 14px; }\n.cs-ab__col p{ font-size: 14px; line-height: 1.7; color: var(--ev-navy-900);\n  font-weight: 300; font-style: italic; margin: 0; }\n.cs-ab__note{ margin-top: 20px !important; font-size: 13px !important; color: var(--ev-muted) !important; }\n@media (max-width: 900px){\n  .cs-ab{ grid-template-columns: 1fr; }\n  .cs-ab__col{ padding: 24px 0 !important; border-right: 0; border-bottom: 1px solid var(--ev-line); }\n  .cs-ab__col:last-child{ border-bottom: 0; }\n}\n\n.cs-cta{\n  background: var(--ev-navy-900); color:#fff; padding: 96px 48px; text-align:left;\n}\n.cs-cta__inner{ max-width: 1360px; margin: 0 auto; display:grid; grid-template-columns: 1fr auto; gap: 48px; align-items: end; }\n.cs-cta h3{ font-size: clamp(1.8rem, 3.5vw, 2.6rem); font-weight: 300; line-height:1.15; letter-spacing:-0.02em; color:#fff; max-width: 800px; }\n.cs-cta h3 em{ font-style:normal; color: var(--ev-accent); font-weight:300; }\n\n@media (max-width: 900px){\n  .cs-hero{ padding: 120px 24px 56px; min-height: 60dvh; }\n  .cs-facts{ padding: 40px 24px; }\n  .cs-facts__inner{ grid-template-columns: repeat(2, 1fr); gap: 32px 0; }\n  .cs-fact{ padding: 0 20px; border-right: 0; }\n  .cs-fact:nth-child(odd){ padding-left: 0; border-right: 1px solid var(--ev-line); }\n  .cs-body{ padding: 72px 24px; }\n  .cs-cta{ padding: 72px 24px; }\n  .cs-cta__inner{ grid-template-columns: 1fr; }\n  .cs-deliv__row{ grid-template-columns: 1fr; gap: 8px; }\n}\n";
